import SourceState from"./State.js";import VectorTile from"./VectorTile.js";import{getTileSetInfo}from"./ogcTileUtil.js";class OGCVectorTile extends VectorTile{constructor(t){super({attributions:t.attributions,attributionsCollapsible:t.attributionsCollapsible,cacheSize:t.cacheSize,format:t.format,overlaps:t.overlaps,projection:t.projection,tileClass:t.tileClass,transition:t.transition,wrapX:t.wrapX,zDirection:t.zDirection,state:SourceState.LOADING});t={url:t.url,projection:this.getProjection(),mediaType:t.mediaType,supportedMediaTypes:t.format.supportedMediaTypes,context:t.context||null};getTileSetInfo(t).then(this.handleTileSetInfo_.bind(this)).catch(this.handleError_.bind(this))}handleTileSetInfo_(t){this.tileGrid=t.grid,this.setTileUrlFunction(t.urlFunction,t.urlTemplate),this.setState(SourceState.READY)}handleError_(t){console.error(t),this.setState(SourceState.ERROR)}}export default OGCVectorTile;